package com.chaobo.scm.supplier.domain.returning;
import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.junit.jupiter.api.Test;import java.math.BigDecimal;import java.util.*;import java.util.concurrent.atomic.AtomicLong;import static org.assertj.core.api.Assertions.*;
class SupplierReturnAggregateTest{private final I ids=new I();@Test void shouldCompleteReturnOnlyAfterReceiptAndSettlement(){var a=create();long line=a.lines().getFirst().id();a.submit(1,ids);a.review(true,null,2,ids);a.requestInventoryLock(2,ids);a.recordInventoryLock(true,"LOCK-1",Map.of(line,bd("10")),null,0,ids);a.supplierConfirm(false,null,3,ids);a.recordOutbound("OUT-1",Map.of(line,bd("10")),0,ids);a.recordWaybill("SHIP-1","WB-1","SF",0,ids);a.recordSigned(Map.of(line,bd("10")),null,0,ids);assertThatThrownBy(()->a.close(2,ids)).hasMessageContaining("结算");a.recordSettlement("SET-1",bd("100"),bd("0"),0,ids);a.close(2,ids);assertThat(a.status()).isEqualTo(SupplierReturnStatus.CLOSED);}@Test void shouldRejectOutboundQuantityAboveLockedQuantity(){var a=create();long line=a.lines().getFirst().id();a.submit(1,ids);a.review(true,null,2,ids);a.requestInventoryLock(2,ids);a.recordInventoryLock(true,"LOCK-1",Map.of(line,bd("8")),null,0,ids);a.supplierConfirm(false,null,3,ids);assertThatThrownBy(()->a.recordOutbound("OUT-1",Map.of(line,bd("9")),0,ids)).hasMessageContaining("锁定数量");}private SupplierReturnAggregate create(){return SupplierReturnAggregate.create(1,2,null,"质量不合格",List.of(new SupplierReturnAggregate.NewLine("SKU-1","B1","UNQUALIFIED",bd("10"))),1,ids);}private static BigDecimal bd(String v){return new BigDecimal(v);}static class I implements IdentifierGenerator{private final AtomicLong n=new AtomicLong();public long nextId(){return n.incrementAndGet();}public String nextBusinessNo(String p){return p+nextId();}}}
